#include <stdio.h>
int main() {
    int N, Q;
    scanf("%d %d", &N, &Q);
    int hills[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &hills[i]);
    }
    while (Q--) {
        int type;
        scanf("%d", &type);
        if (type == 1) {
            int i, k;
            scanf("%d %d", &i, &k);
            i--;
            while (k--) {
                int next = -1;
                for (int j = i + 1; j < N; j++) {
                    if (hills[j] > hills[i]) {
                        next = j;
                        break;
                    }
                }
                if (next == -1 || next - i > 100) {
                    break;
                }
                i = next;
            }
            printf("%d\n", i + 1);
        } else {
            int L, R, X;
            scanf("%d %d %d", &L, &R, &X);
            L--;
            R--;
            for (int i = L; i <= R; i++) {
                hills[i] += X;
            }
        }
    }
    return 0;
}

