import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int Q = sc.nextInt();
        int[] hills = new int[N];
        for (int i = 0; i < N; i++) {
            hills[i] = sc.nextInt();
        }
        while (Q-- > 0) {
            int type = sc.nextInt();
            if (type == 1) {
                int i = sc.nextInt() - 1;
                int k = sc.nextInt();
                while (k-- > 0) {
                    int next = -1;
                    for (int j = i + 1; j < N; j++) {
                        if (hills[j] > hills[i]) {
                            next = j;
                            break;
                        }
                    }
                    if (next == -1 || next - i > 100) {
                        break;
                    }
                    i = next;
                }
                System.out.println(i + 1);
            } else {
                int L = sc.nextInt() - 1;
                int R = sc.nextInt() - 1;
                int X = sc.nextInt();
                for (int i = L; i <= R; i++) {
                    hills[i] += X;
                }
            }
        }
    }
}

